1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("nextGeneration", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single living cell with zero neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent living cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive that has exactly two neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    const sorted = result.map(([x, y]) => `${x},${y}`).sort();
20	    const expected = [[1, -1], [1, 0], [1, 1]].map(([x, y]) => `${x},${y}`).sort();
21	    expect(sorted).toEqual(expected);
22	  });
23	  it("should keep a live cell alive that has exactly three neighbors (survival)", () => {
24	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
25	    expect(result.some(([x, y]) => x === 1 && y === 0)).toBe(true);
26	  });
27	  it("should kill a live cell that has more than three neighbors (overpopulation)", () => {
28	    // Cross pattern: center cell (1,1) has 4 neighbors → dies
29	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]]);
30	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
31	  });
32	  it("should bring a dead cell to life when it has exactly three living neighbors (reproduction)", () => {
33	    // Dead cell (1,1) has exactly 3 living neighbors: (0,0), (1,0), (0,1)
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(true);
36	  });
37	  it.todo("should preserve a block pattern as a still life across one generation");
38	  it.todo("should oscillate a blinker pattern to its alternate phase");
39	  it.todo("should handle cells at negative coordinates");
40	});
