1	type Cell = [number, number];
2	
3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const alive = new Set(cells.map(([x, y]) => `${x},${y}`));
5	  const neighborCounts = new Map<string, number>();
6	
7	  for (const [x, y] of cells) {
8	    for (let dx = -1; dx <= 1; dx++) {
9	      for (let dy = -1; dy <= 1; dy++) {
10	        if (dx === 0 && dy === 0) continue;
11	        const key = `${x + dx},${y + dy}`;
12	        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
13	      }
14	    }
15	  }
16	
17	  const result: Cell[] = [];
18	  for (const [key, count] of neighborCounts) {
19	    if (count === 3 || (count === 2 && alive.has(key))) {
20	      const [x, y] = key.split(",").map(Number);
21	      result.push([x, y]);
22	    }
23	  }
24	
25	  return result;
26	}
